// src/App.js
import React, { useState, useEffect } from "react";
import Dice from "react-dice-roll";

// --- Special Deck Cards ---
const parshaCard = {
  name: "Parsha",
  questions: [
    {
      question: "What day was Adam born?",
      answer: "The 6th day",
      points: 20,
    },
    {
      question: "What day was not 'good' but 'very' good?",
      answer: "The 6th day",
      points: 20,
    },
    {
      question: "Where do we see adding is sometimes subtracting?",
      answer:
        "Adam added 'don't touch' the tree. The snake used this to fool Chava.",
      points: 20,
    },
  ],
};

const harHaBayitCard = {
  name: "Har HaBayit",
  questions: [
    {
      question: 'Which items were housed in the Kodesh ("holy") chamber?',
      answer: "The showbread table, menorah, and incense altar",
      points: 300,
    },
    {
      question:
        "What is the OJ associated with the Omer, the Two Loaves and the Lechem Hapanim?",
      answer: `That never was a disqualifying defect found in any of these 3 holy offerings. Explanation: \na. The Omer, the barley offering brought on the 16th of Nissan, released the new crop for eating if a defect occurred, they wouldn't be able to bring the offering on that day and the new crop would have remained forbidden for the entire year!\nb. If there was a defect in the Two Loaves brought on Shavuos, we would have been unable to bring this offering, and would then have been unable to use the new wheat crop for minchah on the mizbe'ach.\nc. If a defect were found on the 12 loaves of the Lechem HaPanim that were baked before Shabbos, no new loaves would have been able to be set on the Shulchan until the following week.`,
      points: 600,
    },
  ],
};

const mazalCard = {
  name: "Mazal",
  text: `You had a dream of buried treasure in a far-off city. You travelled there and found the spot and began digging. A policeman stopped you, and after you explained the story, he said he had the same dream of a treasure buried under the floorboards of a tailor shop. You realized that he was describing your own house. You dropped the shovel and ran home to discover the treasure buried under your own bed.`,
  reward: 1000,
  rewardType: "money",
};

const tzadikCard = {
  name: "Tzadik",
  questions: [
    {
      question: "Who is called a Tzadik in the Torah?",
      answer: "Noach is called a Tzadik in the Torah.",
      points: 50,
    },
    {
      question: "What is the reward for being a Tzadik?",
      answer: "A Tzadik receives blessing and protection.",
      points: 100,
    },
  ],
};

// --- Board Image path ---
const boardImage = "/torahpoly_board.png";

// --- Sample Properties ---
const sampleProperties = [
  { type: "property", name: "Schem Royal Estates", colorGroup: "red", price: 300, rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 }, buildCost: { house: 200, hotel: 300 }, houses: 0, hotel: false, ownerIndex: null },
  { type: "property", name: "Schem Yoseph Gardens", colorGroup: "red", price: 300, rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 }, buildCost: { house: 200, hotel: 300 }, houses: 0, hotel: false, ownerIndex: null },
  { type: "property", name: "Schem Dream Resorts", colorGroup: "red", price: 300, rent: { base: 50, house1: 100, house2: 650, house3: 750, hotel: 750 }, buildCost: { house: 150, hotel: 250 }, houses: 0, hotel: false, ownerIndex: null },
  { type: "property", name: "Ephraim Hilltops", colorGroup: "yellow", price: 300, rent: { base: 50, house1: 300, house2: 400, house3: 500, hotel: 800 }, buildCost: { house: 50, hotel: 100 }, houses: 0, hotel: false, ownerIndex: null },
];

// --- Board Events ---
const boardEvents = {
  1: { type: "property", card: sampleProperties[0] },
  3: { type: "property", card: sampleProperties[1] },
  4: { type: "property", card: sampleProperties[2] },
  7: { type: "property", card: sampleProperties[3] },
};

// --- Build Board Positions ---
function buildBoardPositions(refSize = 1200, margin = 100, spacesPerSide = 11) {
  const positions = [];
  const step = (refSize - 2 * margin) / (spacesPerSide - 1);

  const topY = margin;
  for (let i = 0; i < spacesPerSide; i++) positions.push({ x: Math.round(margin + i * step), y: topY });
  const rightX = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: rightX, y: Math.round(topY + i * step) });
  const bottomY = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: Math.round(rightX - i * step), y: bottomY });
  const leftX = margin;
  for (let i = 1; i < spacesPerSide - 1; i++) positions.push({ x: leftX, y: Math.round(bottomY - i * step) });

  return positions.slice(0, 44);
}
const referenceSize = 1200;
const defaultBoardPositions = buildBoardPositions(referenceSize, 100, 11);

// --- Calculate Rent ---
const calculateRent = (card) => {
  if (card.hotel) return card.rent.hotel;
  switch (card.houses) {
    case 3: return card.rent.house3;
    case 2: return card.rent.house2;
    case 1: return card.rent.house1;
    default: return card.rent.base;
  }
};

// --- Modal Styles ---
const modalStyles = { 
  overlay: { position: "fixed", top: 0, left: 0, right: 0, bottom: 0, backgroundColor: "rgba(0,0,0,0.5)", display: "flex", justifyContent: "center", alignItems: "center", zIndex: 1000 },
  modal: { backgroundColor: "#fff", padding: 30, borderRadius: 12, minWidth: 300, maxWidth: "90%", textAlign: "center", boxShadow: "0 5px 15px rgba(0,0,0,0.3)" },
  button: { margin: "8px 5px", padding: "8px 15px", borderRadius: 6, border: "none", backgroundColor: "#007bff", color: "#fff", fontSize: 14, cursor: "pointer" }
};

// --- CardQA Modal for Q&A decks ---
function CardQA({ card, onFinish }) {
  const [currentQ, setCurrentQ] = useState(0);
  const [showAnswer, setShowAnswer] = useState(false);
  const [accepted, setAccepted] = useState(
    Array(card.questions ? card.questions.length : 0).fill(false)
  );

  const toggleAnswer = () => setShowAnswer((v) => !v);
  const acceptCorrect = () => {
    setAccepted((prev) => {
      const copy = [...prev];
      copy[currentQ] = true;
      return copy;
    });
  };
  const prevQuestion = () => {
    setShowAnswer(false);
    setCurrentQ((i) => (i > 0 ? i - 1 : i));
  };
  const nextQuestion = () => {
    setShowAnswer(false);
    setCurrentQ((i) => (i < card.questions.length - 1 ? i + 1 : i));
  };
  const totalPoints = accepted.reduce(
    (sum, val, i) => (val ? sum + card.questions[i].points : sum),
    0
  );
  const allCorrect = accepted.every((val) => val === true);

  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>{card.name} Card</h2>
        <p>
          Question {currentQ + 1} of {card.questions.length}
        </p>
        <div style={{ marginTop: 10, marginBottom: 10 }}>
          <p style={{ fontWeight: "bold" }}>{card.questions[currentQ].question}</p>
          {showAnswer ? (
            <p style={{ color: "green", fontWeight: "bold" }}>{card.questions[currentQ].answer}</p>
          ) : (
            <button onClick={toggleAnswer} style={modalStyles.button}>
              Reveal Answer
            </button>
          )}
        </div>
        <div style={{ marginTop: 10 }}>
          <button onClick={prevQuestion} disabled={currentQ === 0} style={modalStyles.button}>
            Previous
          </button>
          <button onClick={nextQuestion} disabled={currentQ === card.questions.length - 1} style={modalStyles.button}>
            Next
          </button>
        </div>
        <div style={{ marginTop: 20 }}>
          {!accepted[currentQ] && showAnswer && (
            <button onClick={acceptCorrect} style={{ ...modalStyles.button, backgroundColor: "#28a745" }}>
              Accept Correct (+{card.questions[currentQ].points} Zchut)
            </button>
          )}
          {accepted[currentQ] && (
            <p style={{ color: "green", fontWeight: "bold" }}>Accepted ✔</p>
          )}
        </div>
        <div style={{ marginTop: 20 }}>
          <p>Total Zchut Points: <strong>{totalPoints}</strong></p>
          {allCorrect ? (
            <p style={{ color: "blue", fontWeight: "bold" }}>All correct! You can finish.</p>
          ) : (
            <p>Continue or finish now.</p>
          )}
        </div>
        <button onClick={() => onFinish(allCorrect, totalPoints, "zchut")} style={modalStyles.button}>
          Finish Q&A
        </button>
      </div>
    </div>
  );
}

// --- Mazal Card Modal ---
function MazalCardModal({ card, onFinish }) {
  const [showReward, setShowReward] = useState(false);
  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>{card.name} Card</h2>
        <p style={{ fontWeight: "bold", whiteSpace: "pre-wrap" }}>{card.text}</p>
        {!showReward ? (
          <button onClick={() => setShowReward(true)} style={modalStyles.button}>
            Reveal Mazal
          </button>
        ) : (
          <p style={{ color: "green", fontWeight: "bold" }}>
            {card.rewardType === "money"
              ? `You won $${card.reward}!`
              : `You gained ${card.reward} Zchut points!`}
          </p>
        )}
        <button onClick={() => onFinish(true, card.reward, card.rewardType)} style={{ ...modalStyles.button, marginTop: 20 }}>
          Close
        </button>
      </div>
    </div>
  );
}

// --- Main App ---
function App() {
  const [players, setPlayers] = useState([]);
  const [newPlayerName, setNewPlayerName] = useState("");
  const [newPlayerColor, setNewPlayerColor] = useState("");
  const [gameStarted, setGameStarted] = useState(false);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [currentCard, setCurrentCard] = useState(null);
  const [qaMode, setQaMode] = useState(false);
  const [zchutPoints, setZchutPoints] = useState(0);
  const [money, setMoney] = useState(0);
  const [boardWidth, setBoardWidth] = useState(Math.min(window.innerWidth * 0.95, referenceSize));
  const [boardPositions, setBoardPositions] = useState(defaultBoardPositions);

  const availableColors = ["black","purple","blue","brown","orange","red","green"];
  const maxPlayers = 7;
  const scale = boardWidth / referenceSize;

  useEffect(() => {
    const handleResize = () => setBoardWidth(Math.min(window.innerWidth * 0.95, referenceSize));
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const addPlayer = () => {
    if (!newPlayerName || !newPlayerColor) return;
    if (players.some(p => p.color === newPlayerColor)) { alert("Color taken!"); return; }
    setPlayers([...players, { name: newPlayerName, color: newPlayerColor, position: 0, zchutPoints: 1000, money: 2000, missTurn: false, index: players.length }]);
    setNewPlayerName("");
    setNewPlayerColor("");
  };

  const startGame = () => {
    if (players.length < 2) { alert("At least 2 players required."); return; }
    setGameStarted(true);
  };

  const movePlayerBy = (steps) => {
    if (steps <= 0 || players.length === 0) return;
    const updatedPlayers = [...players];
    const startIndex = updatedPlayers[currentPlayerIndex].position;
    updatedPlayers[currentPlayerIndex].position = (startIndex + steps) % boardPositions.length;
    setPlayers(updatedPlayers);

    // Trigger Card Modal if property
    const landedIndex = updatedPlayers[currentPlayerIndex].position;
    const event = boardEvents[landedIndex];
    if (event?.type === "property") setCurrentCard(event.card);
  };

  // --- Special Deck Modal Logic ---
  const finishQA = (allCorrect, points, rewardType = "zchut") => {
    setQaMode(false);
    if (rewardType === "zchut") {
      setZchutPoints((prev) => prev + points);
    } else if (rewardType === "money") {
      setMoney((prev) => prev + points);
    }
    setCurrentCard(null);
  };

  const rollDice = (val) => {
    movePlayerBy(val); // simple for now
  };

  const endTurn = () => setCurrentPlayerIndex((prev) => (players.length > 0 ? (prev + 1) % players.length : 0));

  return (
    <div style={{ fontFamily: "Arial, sans-serif", padding: 20, backgroundColor: "#f0f2f5", minHeight: "100vh", textAlign: "center" }}>
      <h1>TorahPoly Monopoly Game</h1>

      {!gameStarted ? (
        <>
          {players.length < maxPlayers && (
            <div style={{ display: "flex", justifyContent: "center", gap: 10, marginBottom: 20 }}>
              <input type="text" placeholder="Player Name" value={newPlayerName} onChange={(e)=>setNewPlayerName(e.target.value)} style={{ fontSize:16, padding:"5px 10px", borderRadius:4, border:"1px solid #ccc"}} />
              <select value={newPlayerColor} onChange={(e)=>setNewPlayerColor(e.target.value)} style={{ fontSize:16, padding:"5px 10px", borderRadius:4, border:"1px solid #ccc"}}>
                <option value="">Choose Color</option>
                {availableColors.filter(c => !players.some(p => p.color===c)).map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <button onClick={addPlayer} style={{ backgroundColor:"#007bff", color:"white", border:"none", borderRadius:8, padding:"10px 20px", cursor:"pointer"}}>Add Player</button>
            </div>
          )}
          <h2>Joined Players ({players.length}/{maxPlayers})</h2>
          <ul>
            {players.map((p,i) => <li key={i} style={{ color:p.color, fontWeight:i===currentPlayerIndex?"bold":"normal"}}>{p.name} ({p.color})</li>)}
          </ul>
          <button onClick={startGame} style={{ backgroundColor:"#007bff", color:"white", border:"none", borderRadius:8, padding:"10px 20px", marginTop:20, cursor:"pointer"}}>Start Game</button>
        </>
      ) : (
        <>
          <div style={{ marginBottom:20 }}>
            <h2>Players</h2>
            <ul>
              {players.map((p,i) => <li key={i} style={{ color:p.color, fontWeight:i===currentPlayerIndex?"bold":"normal"}}>{p.name} - Position: {p.position}, Money: ${p.money}, Zchut: {p.zchutPoints} {i===currentPlayerIndex?"(Your Turn)":""}</li>)}
            </ul>
          </div>

          {/* Board with Special Deck Buttons */}
          <div style={{ position:"relative", display:"inline-block", marginBottom:20 }}>
            <img src={boardImage} alt="Board" style={{ width:boardWidth, maxWidth:"95vw", height:"auto", border:"2px solid #333", borderRadius:12 }} />
            {players.map((p,idx) => {
              const pos = boardPositions[p.position % boardPositions.length];
              const left = Math.round(pos.x * scale - 12);
              const top = Math.round(pos.y * scale - 12);
              return (
                <div key={idx} title={p.name} style={{ position:"absolute", left, top, width:24, height:24, borderRadius:"50%", backgroundColor:p.color, border:idx===currentPlayerIndex?"3px solid gold":"1px solid #000", display:"flex", justifyContent:"center", alignItems:"center", fontSize:12, color:"#fff" }}>{idx+1}</div>
              );
            })}

            {/* Special Deck Buttons */}
            <button
              onClick={() => setCurrentCard(mazalCard)}
              style={{
                position: "absolute",
                top: "20%",
                left: "38%",
                transform: "translate(-50%, -50%)",
                padding: "6px 12px",
                fontSize: 14,
                backgroundColor: "#28a745",
                color: "#fff",
                border: "2px solid #000",
                borderRadius: 6,
                cursor: "pointer",
                zIndex: 2,
              }}
            >
              Mazal Deck
            </button>
            <button
              onClick={() => setCurrentCard(harHaBayitCard)}
              style={{
                position: "absolute",
                top: "20%",
                left: "62%",
                transform: "translate(-50%, -50%)",
                padding: "6px 12px",
                fontSize: 14,
                backgroundColor: "#6f42c1",
                color: "#fff",
                border: "2px solid #000",
                borderRadius: 6,
                cursor: "pointer",
                zIndex: 2,
              }}
            >
              Har HaBayit Deck
            </button>
            <button
              onClick={() => setCurrentCard(tzadikCard)}
              style={{
                position: "absolute",
                top: "43%",
                left: "54%",
                transform: "translate(-50%, -50%)",
                padding: "6px 12px",
                fontSize: 14,
                backgroundColor: "#ffc107",
                color: "#000",
                border: "2px solid #333",
                borderRadius: 6,
                cursor: "pointer",
                zIndex: 2,
              }}
            >
              Tzadik Deck
            </button>
            <button
              onClick={() => setCurrentCard(parshaCard)}
              style={{
                position: "absolute",
                top: "58%",
                left: "70%",
                transformOrigin: "left center",
                transform: "translate(-50%, -50%) rotateX(40deg)",
                padding: "6px 12px",
                fontSize: 14,
                backgroundColor: "#17a2b8",
                color: "#fff",
                border: "2px solid #000",
                borderRadius: 6,
                cursor: "pointer",
                zIndex: 2,
              }}
            >
              Parsha Deck
            </button>
          </div>

          {/* Dice */}
          <div style={{ marginTop:20 }}>
            <h2>Roll Dice</h2>
            <Dice sides={6} onRoll={rollDice} rollTime={1}/>
            <button onClick={endTurn} style={{ backgroundColor:"#007bff", color:"white", border:"none", borderRadius:8, padding:"10px 20px", marginTop:15, cursor:"pointer"}}>End Turn</button>
          </div>
        </>
      )}

      {/* Card Modal for Properties or Special Decks */}
      {currentCard && (
        // If Mazal, show MazalCardModal; if Parsha/Har HaBayit/Tzadik, show CardQA; else show property modal
        currentCard.name === "Mazal" ? (
          <MazalCardModal card={currentCard} onFinish={finishQA} />
        ) : currentCard.name === "Parsha" || currentCard.name === "Har HaBayit" || currentCard.name === "Tzadik" ? (
          <CardQA card={currentCard} onFinish={finishQA} />
        ) : (
          <div style={modalStyles.overlay}>
            <div style={modalStyles.modal}>
              <h2>{currentCard.name}</h2>
              <p>Price: ${currentCard.price}</p>
              <p>Rent: ${currentCard.rent.base}</p>
              <p>Owner: {currentCard.ownerIndex !== null ? `Player ${currentCard.ownerIndex + 1}` : "None"}</p>
              <button style={modalStyles.button} onClick={() => setCurrentCard(null)}>Close</button>
            </div>
          </div>
        )
      )}
      <div style={{ marginTop: 20 }}>
        <p>Total Zchut Points: <strong>{zchutPoints}</strong></p>
        <p>Money: <strong>${money}</strong></p>
      </div>
    </div>
  );
}

export default App;
